import{_ as i,a as e,b as l}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as o,o as t,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"認證管理與登入裝置管理","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Safety/authentication-and-login-devices.md","filePath":"zh-TW/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),h={name:"zh-TW/Safety/authentication-and-login-devices.md"};function n(s,a,d,c,u,b){return t(),r("div",null,[...a[0]||(a[0]=[p('<h1 id="認證管理與登入裝置管理" tabindex="-1">認證管理與登入裝置管理 <a class="header-anchor" href="#認證管理與登入裝置管理" aria-label="Permalink to &quot;認證管理與登入裝置管理&quot;">​</a></h1><p>安全設定裡的「認證管理」和「登入裝置管理」，主要用來保護 ImgBed 後台、首頁上傳入口和 WebDAV 存取。</p><p>你可以在這裡設定存取密碼，也可以查看哪些裝置登入過，必要時讓舊裝置登出。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>進入後台後打開：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系統設定 -&gt; 安全設定</span></span></code></pre></div><p>頁面裡會看到兩個主要區塊：</p><ul><li>認證管理</li><li>登入裝置管理</li></ul><p><img src="'+i+'" alt="認證管理畫面" loading="lazy"></p><h2 id="認證管理是做什麼的" tabindex="-1">認證管理是做什麼的 <a class="header-anchor" href="#認證管理是做什麼的" aria-label="Permalink to &quot;認證管理是做什麼的&quot;">​</a></h2><p>認證管理用來設定存取憑證。</p><p>目前分成兩類：</p><ul><li>使用者端認證</li><li>管理端認證</li></ul><h2 id="使用者端認證" tabindex="-1">使用者端認證 <a class="header-anchor" href="#使用者端認證" aria-label="Permalink to &quot;使用者端認證&quot;">​</a></h2><p>使用者端認證對應「上傳密碼」。</p><p>設定上傳密碼後，普通使用者進入上傳頁時需要輸入密碼。適合你不想讓任何人都能直接上傳圖片的情境。</p><p><img src="'+e+'" alt="使用者端登入畫面" loading="lazy"></p><h3 id="設定上傳密碼" tabindex="-1">設定上傳密碼 <a class="header-anchor" href="#設定上傳密碼" aria-label="Permalink to &quot;設定上傳密碼&quot;">​</a></h3><p>如果填了上傳密碼：</p><ul><li>使用者進入上傳頁時需要輸入密碼。</li><li>密碼正確後才能使用上傳功能。</li><li>如果開啟使用者端裝置工作階段，系統會記錄這台裝置。</li></ul><p>如果你修改上傳密碼，舊的使用者端登入狀態會失效，使用者需要重新輸入新密碼。</p><h2 id="管理端認證" tabindex="-1">管理端認證 <a class="header-anchor" href="#管理端認證" aria-label="Permalink to &quot;管理端認證&quot;">​</a></h2><p>管理端認證對應「使用者名稱」和「密碼」。</p><p>這是後台管理頁的登入保護。正式使用時建議一定要設定。</p><p><img src="'+l+'" alt="管理端登入畫面" loading="lazy"></p><h3 id="設定管理端認證" tabindex="-1">設定管理端認證 <a class="header-anchor" href="#設定管理端認證" aria-label="Permalink to &quot;設定管理端認證&quot;">​</a></h3><p>如果填了管理端使用者名稱和密碼：</p><ul><li>進入後台需要登入。</li><li>登入成功後會記錄管理端裝置。</li><li>可以在登入裝置管理裡查看、清理或強制裝置登出。</li></ul><p>如果修改管理端帳號或密碼，舊的後台登入狀態會失效，需要重新登入。</p><h2 id="登入裝置管理是做什麼的" tabindex="-1">登入裝置管理是做什麼的 <a class="header-anchor" href="#登入裝置管理是做什麼的" aria-label="Permalink to &quot;登入裝置管理是做什麼的&quot;">​</a></h2><p>登入裝置管理用來查看和管理已登入過的裝置。</p><p>它可以幫你確認：</p><ul><li>哪些裝置登入過後台。</li><li>哪些裝置使用過首頁上傳入口。</li><li>哪些 WebDAV 用戶端連過站台。</li><li>某個裝置是否仍有效。</li><li>是否需要讓舊裝置登出。</li></ul><p>頁面裡有三個分頁：</p><ul><li>管理端</li><li>使用者端</li><li>WebDAV</li></ul><h2 id="全域-cookie-安全設定" tabindex="-1">全域 Cookie 安全設定 <a class="header-anchor" href="#全域-cookie-安全設定" aria-label="Permalink to &quot;全域 Cookie 安全設定&quot;">​</a></h2><p>登入裝置管理上方有一組全域 Cookie 設定。</p><h3 id="使用者端-cookie-有效天數" tabindex="-1">使用者端 Cookie 有效天數 <a class="header-anchor" href="#使用者端-cookie-有效天數" aria-label="Permalink to &quot;使用者端 Cookie 有效天數&quot;">​</a></h3><p>控制使用者端登入狀態可以保留幾天。</p><p>例如設定 14 天，使用者登入後 14 天內通常不需要重複輸入上傳密碼。</p><h3 id="管理端-cookie-有效天數" tabindex="-1">管理端 Cookie 有效天數 <a class="header-anchor" href="#管理端-cookie-有效天數" aria-label="Permalink to &quot;管理端 Cookie 有效天數&quot;">​</a></h3><p>控制管理端登入狀態可以保留幾天。</p><p>例如設定 14 天，管理員登入後台後 14 天內通常不需要重新登入。</p><h3 id="secure-模式" tabindex="-1">Secure 模式 <a class="header-anchor" href="#secure-模式" aria-label="Permalink to &quot;Secure 模式&quot;">​</a></h3><p>開啟 Secure 模式後，瀏覽器只會在 HTTPS 連線時帶上登入 Cookie。</p><p>正式 HTTPS 站台建議開啟。本機 HTTP 測試時不建議開，否則可能出現「登入成功，但重新整理後又被登出」。</p><h2 id="管理端登入裝置" tabindex="-1">管理端登入裝置 <a class="header-anchor" href="#管理端登入裝置" aria-label="Permalink to &quot;管理端登入裝置&quot;">​</a></h2><p>管理端分頁會顯示後台登入裝置。</p><p>只有設定管理端帳號密碼，並成功登入後台後，才會出現裝置紀錄。</p><p>裝置卡片會顯示：</p><ul><li>裝置和瀏覽器資訊</li><li>首次登入 IP</li><li>最近活動 IP</li><li>登入時間</li><li>最後活動時間</li><li>到期時間</li><li>目前狀態</li></ul><p>如果看到陌生裝置，可以按「強制登出」讓它失效。</p><h2 id="清理舊裝置" tabindex="-1">清理舊裝置 <a class="header-anchor" href="#清理舊裝置" aria-label="Permalink to &quot;清理舊裝置&quot;">​</a></h2><p>「清理舊裝置」會批次清理目前類型下的舊登入紀錄。</p><p>如果你懷疑帳號在其他裝置仍保持登入，可以用這個按鈕快速清理。</p><h2 id="強制登出" tabindex="-1">強制登出 <a class="header-anchor" href="#強制登出" aria-label="Permalink to &quot;強制登出&quot;">​</a></h2><p>「強制登出」用來讓單一裝置失效。</p><p>被強制登出後：</p><ul><li>管理端裝置需要重新登入後台。</li><li>使用者端裝置需要重新輸入上傳密碼。</li><li>WebDAV 用戶端需要重新認證。</li></ul><p>如果裝置已過期或失效，也可以清掉對應紀錄。</p><h2 id="登出目前裝置" tabindex="-1">登出目前裝置 <a class="header-anchor" href="#登出目前裝置" aria-label="Permalink to &quot;登出目前裝置&quot;">​</a></h2><p>目前裝置卡片上會顯示「目前裝置」標記。</p><p>點擊登出目前裝置後：</p><ul><li>管理端會退出目前後台登入。</li><li>使用者端會退出目前使用者端登入。</li></ul><p>登出後需要重新登入才能繼續使用。</p>',65)])])}const f=o(h,[["render",n]]);export{q as __pageData,f as default};
